// Three implementations of 'reverse an array'.
// Same time complexity. Very different space.

// (1) Two-pointer in-place swap — O(1) extra space
function reverseInPlace(arr) {
  let l = 0, r = arr.length - 1;
  while (l < r) {
    [arr[l], arr[r]] = [arr[r], arr[l]];
    l++; r--;
  }
  return arr;
}

// (2) Build a new array — O(n) extra space
function reverseCopy(arr) {
  const out = [];
  for (let i = arr.length - 1; i >= 0; i--) {
    out.push(arr[i]);
  }
  return out;
}

// (3) Recursive — O(n) extra space (call stack frames!)
function reverseRecursive(arr) {
  if (arr.length <= 1) return arr;
  return [arr[arr.length - 1], ...reverseRecursive(arr.slice(0, -1))];
}

// All O(n) time. But:
//   (1) uses O(1) extra memory  ← best for big arrays
//   (2) uses O(n) — doubles peak memory
//   (3) uses O(n) — and has stack-overflow risk for large n

console.log(reverseInPlace([1, 2, 3, 4, 5]));
console.log(reverseCopy([1, 2, 3, 4, 5]));
console.log(reverseRecursive([1, 2, 3, 4, 5]));

