function hasDuplicates(arr) {
  const seen = new Set();
  for (const x of arr) {
    if (seen.has(x)) return true;
    seen.add(x);
  }
  return false;
}

function hasDuplicatesSorted(arr) {
  arr.sort((a, b) => a - b);  // O(n log n) time
  for (let i = 1; i < arr.length; i++) {
    if (arr[i] === arr[i - 1]) return true;
  }
  return false;
}

