// Iterative Fibonacci — keeps only the last two values.
// O(n) time, O(1) space.
function fibIterative(n) {
  if (n < 2) return n;
  let a = 0, b = 1;
  for (let i = 2; i <= n; i++) {
    [a, b] = [b, a + b];
  }
  return b;
}

// Memoized recursive Fibonacci.
// O(n) time, O(n) space — both for the memo and the call stack.
function fibMemo(n, memo = {}) {
  if (n < 2) return n;
  if (memo[n] !== undefined) return memo[n];
  return (memo[n] = fibMemo(n - 1, memo) + fibMemo(n - 2, memo));
}

// Naive recursive Fibonacci — DON'T DO THIS.
// O(2ⁿ) time. O(n) space (recursion depth).
function fibNaive(n) {
  if (n < 2) return n;
  return fibNaive(n - 1) + fibNaive(n - 2);
}

console.log('Iterative fib(30) =', fibIterative(30));
console.log('Memoized fib(30) =', fibMemo(30));
console.log('Naive recursive fib(30) =', fibNaive(30));
// Try fib(50) with the naive version — it will hang.
// The other two return instantly.

